  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 2rem;
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 1rem;
}

/* Individual team card (closed state) */
.team-card-compact {
  background: white;
  border-radius: 16px;
  padding: 2rem;
  text-align: center;
  cursor: pointer;
  transition: all 0.4s cubic-bezier(0.4, 0, 0.2, 1);
  border: 1px solid #eee;
  position: relative;
  overflow: hidden;
}

.team-card-compact:hover {
  transform: translateY(-8px);
  box-shadow: 0 20px 40px rgba(0, 43, 92, 0.15);
}

/* Photo styling */
.team-photo {
  width: 120px;
  height: 120px;
  border-radius: 50%;
  object-fit: cover;
  margin: 0 auto 1.5rem;
  border: 4px solid var(--color-gold);
  transition: all 0.4s ease;
}

/* Name and role */
.team-name-compact {
  font-size: 1.25rem;
  font-weight: 700;
  color: var(--color-navy);
  margin-bottom: 0.5rem;
}

.team-role-compact {
  font-size: 0.9rem;
  color: var(--color-gold-dark);
  font-weight: 600;
  margin-bottom: 1rem;
}

/* Badges container */
.team-badges-compact {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: 0.5rem;
  margin-top: 1rem;
}

/* Expanded bio panel (hidden by default) */
.team-bio-full {
  max-height: 0;
  overflow: hidden;
  opacity: 0;
  transition: all 0.6s cubic-bezier(0.4, 0, 0.2, 1);
  margin-top: 0;
  padding: 0 2rem;
}

/* Active/expanded state */
.team-card-compact.active {
  position: fixed;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  width: 90%;
  max-width: 900px;
  max-height: 90vh;
  overflow-y: auto;
  z-index: 1000;
  box-shadow: 0 25px 50px rgba(0, 0, 0, 0.25);
}

.team-card-compact.active .team-photo {
  width: 100px;
  height: 100px;
  margin-top: 1rem;
}

.team-card-compact.active .team-bio-full {
  max-height: 2000px;
  opacity: 1;
  margin-top: 2rem;
  padding: 2rem;
  background: #f8f9fa;
  border-radius: 12px;
}

/* Overlay when card is active */
.overlay {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: rgba(0, 43, 92, 0.8);
  opacity: 0;
  visibility: hidden;
  transition: all 0.3s ease;
  z-index: 999;
}

.overlay.active {
  opacity: 1;
  visibility: visible;
}

/* Close button */
.close-btn {
  position: absolute;
  top: 1.5rem;
  right: 1rem;
  width: 40px;
  height: 40px;
  border-radius: 50%;
  background: var(--color-navy);
  color: white;
  border: none;
  font-size: 1.5rem;
  cursor: pointer;
  opacity: 0;
  transition: opacity 0.3s ease;
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1001;
}

.team-card-compact.active .close-btn {
  opacity: 1;
}

/* Bio text styling */
.bio-text {
  color: #444;
  font-size: 0.95rem;
  line-height: 1.8;
  margin-bottom: 1rem;
}

/* Scrollbar for active card */
.team-card-compact.active::-webkit-scrollbar {
  width: 8px;
}

.team-card-compact.active::-webkit-scrollbar-thumb {
  background: var(--color-gold);
  border-radius: 4px;
}

/* Responsive */
@media (max-width: 768px) {
  .team-grid {
    grid-template-columns: 1fr;
  }

  .team-card-compact.active {
    width: 95%;
